async function applyService(copy: ServiceCopy) {
  const svc = await sql`SELECT id FROM services WHERE slug = ${copy.slug} LIMIT 1`;
  if (!svc[0]) { console.error(`✗ ${copy.slug} not found`); return; }
  const id = svc[0].id as string;
  await sql`UPDATE services SET summary_uk=${copy.summary.uk}, summary_ru=${copy.summary.ru}, summary_en=${copy.summary.en} WHERE id=${id}`;
  await sql`DELETE FROM content_sections WHERE owner_type='service' AND owner_id=${id}`;
  await sql`DELETE FROM faq_items WHERE owner_type='service' AND owner_id=${id}`;
  const sectionIds: string[] = [];
  for (let i = 0; i < copy.sections.length; i++) {
    const s = copy.sections[i]; const sid = randomUUID(); sectionIds.push(sid);
    const data = { heading: s.heading, body: s.body, calloutBody: s.calloutBody, heroImage: null };
    await sql`INSERT INTO content_sections (id, owner_type, owner_id, sort_order, section_type, data) VALUES (${sid}, 'service', ${id}, ${i}, 'richText'::section_type, ${JSON.stringify(data)}::jsonb)`;
  }
  for (let i = 0; i < copy.faq.length; i++) {
    const f = copy.faq[i];
    await sql`INSERT INTO faq_items (owner_type, owner_id, sort_order, question_uk, question_ru, question_en, answer_uk, answer_ru, answer_en) VALUES ('service', ${id}, ${i}, ${f.question.uk}, ${f.question.ru}, ${f.question.en}, ${f.answer.uk}, ${f.answer.ru}, ${f.answer.en})`;
  }
  const order = [...sectionIds.map((s) => `section:${s}`), "faq", "doctors", "equipment", "relatedServices", "finalCTA"];
  await sql`UPDATE services SET block_order=${order} WHERE id=${id}`;
  console.log(`✓ ${copy.slug} — ${copy.sections.length} sections, ${copy.faq.length} FAQs`);
}

async function main() {
  for (const c of [juvederm, polyphil]) await applyService(c);
  await sql.end();
  console.log("\nV2 DONE — all 10 injectable-cosmetology services have TZ-aligned copy. Reply \"continue to V3\" for apparatus cosmetology (EMFACE, EMSCULPT NEO, Ultraformer, HydraFacial, and others).");
}
main().catch((e) => { console.error(e); process.exit(1); });
